int numTilings(int n) {
    const int MOD=1000000007;
    if(n==1) return 1;
    long long a=1,b=2,c=5;
    if(n==2) return 2; if(n==3) return 5;
    for(int i=4;i<=n;i++){ long long d=(2*b+c)%MOD; a=b; b=c; c=d; } return (int)c;
